		return isset($_POST['mufu_action']) && $_POST['mufu_action'] === 'delete' && isset($_POST['mufu_file_id']);
	}

	public function handle_upload() {
		if (!is_user_logged_in()) return;

		if ($this->is_upload_request()) {
			if (!isset($_POST[self::NONCE_FIELD]) || !wp_verify_nonce($_POST[self::NONCE_FIELD], self::NONCE_ACTION)) {
				$this->set_flash('error', 'Security check failed.');
				return;
			}

			$user_id = get_current_user_id();
			$type = isset($_POST['mufu_type']) ? sanitize_key($_POST['mufu_type']) : 'document';
			if (!in_array($type, ['profile', 'document'], true)) $type = 'document';

			$field = ($type === 'profile') ? 'mufu_profile' : 'mufu_document';
			if (empty($_FILES[$field]) || empty($_FILES[$field]['name'])) {
				$this->set_flash('error', 'No file selected.');
				return;
			}

			$max_bytes = (int) apply_filters('mufu_max_upload_bytes', 25 * 1024 * 1024, $type, $user_id);
			if (!empty($_FILES[$field]['size']) && (int) $_FILES[$field]['size'] > $max_bytes) {
				$this->set_flash('error', 'File is too large.');
				return;
			}

			require_once ABSPATH . 'wp-admin/includes/file.php';
			require_once ABSPATH . 'wp-admin/includes/image.php';

			add_filter('upload_dir', [$this, 'filter_upload_dir']);

			$overrides = [
				'test_form' => false,
				'mimes'     => $this->allowed_mimes(),
			];

			$file = $_FILES[$field];
			$upload = wp_handle_upload($file, $overrides);

			remove_filter('upload_dir', [$this, 'filter_upload_dir']);

			if (isset($upload['error'])) {
				$this->set_flash('error', $upload['error']);
				return;
			}

			$url  = $upload['url'];
			$path = $upload['file'];
			$mime = isset($upload['type']) ? $upload['type'] : '';

			$meta = [
				'id'       => wp_generate_uuid4(),
				'type'     => $type,
				'url'      => esc_url_raw($url),
				'path'     => $path,
				'mime'     => sanitize_text_field($mime),
				'name'     => sanitize_file_name(basename($path)),
				'original' => sanitize_file_name($file['name']),
				'size'     => (int) filesize($path),
				'time'     => time(),
			];

			if ($type === 'profile') {
				$old = get_user_meta($user_id, 'mufu_profile_file', true);
				if (is_array($old) && !empty($old['path']) && $this->is_path_in_user_files($old['path'])) {
					@unlink($old['path']);
				}
				update_user_meta($user_id, 'mufu_profile_file', $meta);
				update_user_meta($user_id, 'mufu_profile_url', $meta['url']);
			} else {
				$list = get_user_meta($user_id, 'mufu_documents', true);
				if (!is_array($list)) $list = [];
				$list[] = $meta;
				update_user_meta($user_id, 'mufu_documents', $list);
			}

			$this->set_flash('success', 'Upload successful.');
			$this->safe_redirect_back();
			exit;
		}

		if ($this->is_delete_request()) {
			if (!isset($_POST[self::NONCE_FIELD]) || !wp_verify_nonce($_POST[self::NONCE_FIELD], self::NONCE_ACTION)) {
				$this->set_flash('error', 'Security check failed.');
				return;
			}

			$user_id = get_current_user_id();
			$file_id = sanitize_text_field(wp_unslash($_POST['mufu_file_id']));
			$list = get_user_meta($user_id, 'mufu_documents', true);
			if (!is_array($list)) $list = [];

			$found = false;
			$new = [];
			foreach ($list as $item) {
				if (is_array($item) && isset($item['id']) && hash_equals((string)$item['id'], (string)$file_id)) {
					$found = true;
					if (!empty($item['path']) && $this->is_path_in_user_files($item['path'])) {
						@unlink($item['path']);
					}
					continue;
				}
				$new[] = $item;
			}

			if ($found) {
				update_user_meta($user_id, 'mufu_documents', $new);
				$this->set_flash('success', 'File deleted.');
			} else {
				$this->set_flash('error', 'File not found.');
			}

			$this->safe_redirect_back();
			exit;
		}
	}

