	public function filter_upload_dir($dirs) {
		$subdir = '/user-files';
		$dirs['subdir'] = $subdir;
		$dirs['path']   = $dirs['basedir'] . $subdir;
		$dirs['url']    = $dirs['baseurl'] . $subdir;
		return $dirs;
	}

	public function prefilter_upload($file) {
		if (!is_user_logged_in()) {
			$file['error'] = 'You must be logged in to upload files.';
			return $file;
		}

		$allowed = $this->allowed_mimes();
		$ext = strtolower(pathinfo($file['name'], PATHINFO_EXTENSION));
		if ($ext === '') {
			$file['error'] = 'File extension is missing.';
			return $file;
		}

		$ok = false;
		foreach ($allowed as $k => $v) {
			$exts = explode('|', $k);
			if (in_array($ext, $exts, true)) {
				$ok = true;
				break;
			}
		}
		if (!$ok) {
			$file['error'] = 'File type not allowed.';
			return $file;
		}

		return $file;
	}

	public function check_filetype_and_ext($data, $file, $filename, $mimes) {
		$allowed = $this->allowed_mimes();
		$wp_filetype = wp_check_filetype($filename, $allowed);
		if (!empty($wp_filetype['ext']) && !empty($wp_filetype['type'])) {
			$data['ext']  = $wp_filetype['ext'];
			$data['type'] = $wp_filetype['type'];
		}
		return $data;
	}

	private function allowed_mimes() {
		$base = [
			'jpg|jpeg|jpe' => 'image/jpeg',
			'png'          => 'image/png',
			'gif'          => 'image/gif',
			'webp'         => 'image/webp',
			'pdf'          => 'application/pdf',
			'doc'          => 'application/msword',
			'docx'         => 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
			'xls'          => 'application/vnd.ms-excel',
			'xlsx'         => 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
			'ppt'          => 'application/vnd.ms-powerpoint',
			'pptx'         => 'application/vnd.openxmlformats-officedocument.presentationml.presentation',
			'txt'          => 'text/plain',
			'rtf'          => 'application/rtf',
		];

		return (array) apply_filters('mufu_allowed_mimes', $base);
	}

	private function accept_attr() {
		$allowed = $this->allowed_mimes();
		$exts = [];
		foreach ($allowed as $k => $v) {
			foreach (explode('|', $k) as $e) $exts[] = '.' . $e;
		}
		$exts = array_values(array_unique($exts));
		return implode(',', $exts);
	}

	private function is_path_in_user_files($path) {
		$uploads = wp_get_upload_dir();
		$base = trailingslashit($uploads['basedir']) . 'user-files/';
		$real_base = realpath($base);
		$real_path = realpath($path);
		if (!$real_base || !$real_path) return false;
		return str_starts_with($real_path, $real_base);
	}

	private function set_flash($type, $message) {
		if (!session_id()) {
			if (!headers_sent()) @session_start();
		}
		if (session_id()) {
			$_SESSION['mufu_flash'] = [
				'type' => $type,
				'message' => $message,
			];
		} else {
			set_transient('mufu_flash_' . get_current_user_id(), ['type' => $type, 'message' => $message], 60);
		}
	}

	private function get_flash() {
		$data = null;

		if (!session_id()) {
			if (!headers_sent()) @session_start();
		}
		if (session_id() && isset($_SESSION['mufu_flash'])) {
			$data = $_SESSION['mufu_flash'];
			unset($_SESSION['mufu_flash']);
			return $data;
		}

		if (is_user_logged_in()) {
			$key = 'mufu_flash_' . get_current_user_id();
			$data = get_transient($key);
			if ($data) delete_transient($key);
		}

		return is_array($data) ? $data : [];
	}

	private function safe_redirect_back() {
		$ref = wp_get_referer();
		if (!$ref) $ref = home_url('/');
		wp_safe_redirect($ref);
	}

	private function human_bytes($bytes) {
		$bytes = (int) $bytes;
		if ($bytes < 1024) return $bytes . ' B';
		$units = ['KB','MB','GB','TB'];
		$val = $bytes / 1024;
		$u = 0;
		while ($val >= 1024 && $u < count($units) - 1) {
			$val /= 1024;
			$u++;
		}
		return round($val, 2) . ' ' . $units[$u];
	}

