	public function ajax_delete_file() {
		if (!is_user_logged_in()) wp_send_json_error(['message' => 'Not logged in.'], 401);
		check_ajax_referer(self::NONCE_ACTION, 'nonce');

		$user_id = get_current_user_id();
		$file_id = isset($_POST['file_id']) ? sanitize_text_field(wp_unslash($_POST['file_id'])) : '';
		if ($file_id === '') wp_send_json_error(['message' => 'Missing file id.'], 400);

		$list = get_user_meta($user_id, 'mufu_documents', true);
		if (!is_array($list)) $list = [];

		$found = false;
		$new = [];
		foreach ($list as $item) {
			if (is_array($item) && isset($item['id']) && hash_equals((string)$item['id'], (string)$file_id)) {
				$found = true;
				if (!empty($item['path']) && $this->is_path_in_user_files($item['path'])) {
					@unlink($item['path']);
				}
				continue;
			}
			$new[] = $item;
		}

		if (!$found) wp_send_json_error(['message' => 'File not found.'], 404);

		update_user_meta($user_id, 'mufu_documents', $new);
		wp_send_json_success(['message' => 'Deleted.']);
	}
}

